var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"표정이 왜 그래, 레지나? 집에 돌아온 게 후회돼?","JPN":"どうかした？　レジーナ。家に帰ってきたこと、後悔してるの？","ENG":"Why the long face, Regina? Are you regretting coming back home?","TWN":"你怎麼這副表情，蕾佳娜？後悔回家了嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 후회는 하루에도 몇 번씩 했죠.","JPN":"後悔なんて一日何度もしていましたわ。","ENG":"That, I have regretted multiple times a day.","TWN":"這樣的後悔，每天在我的腦海中都要上演很多次。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지하실에서 먼지 쌓인 책장을 넘길 때도, 학회원들이 이해할 수 없는 짓을 일삼을 때도.","JPN":"地下室で埃が溜まった本をめくる時にも、学会員が訳のわからないことをする時にも。","ENG":"Whenever I flip through the dusty pages in the basement, or when the Society members do things I do not understand.","TWN":"在地下室弄倒堆滿灰塵的書架時，學會成員們做出那些讓我無法理解的事時。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그치. 앞으로도 틈만 나면 하게 될 거야.","JPN":"そうだね。これからも暇さえあれば後悔するようになるよ。","ENG":"Yeah. I bet you'll be doing it whenever you can in the future.","TWN":"好吧，那以後有空，你還是會後悔的。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"하지만 자기가 불쌍하다고 착각하지만 마. 넌 이미 남들이 보기에 훌륭한 악당이거든.","JPN":"でも、間違っても自分がかわいそうだなんて思わないでよね。他の人から見たら立派な悪党なんだからさ。","ENG":"But don't think that you're pathetic. In the eyes of others, you're already an excellent villain.","TWN":"但是別以為自己很無辜。因為你已經是別人眼中的優秀壞人了。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"How come?","TWN":"為什麼呢？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"이 지경까지 왔는데 학회를 없애 버리겠다는 발상은 절대 안 떠올리잖아.","JPN":"こんな状況になったのに、学会をなくすって発想はまったくないじゃん。","ENG":"You've come this far, but you haven't thought about getting rid of the Society, right?","TWN":"因為都已經到這種地步了，你也絕對沒想過要消滅學會不是嘛。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"보통은 한 놈이라도 더 많이 죽이고 싶어하는 게 정상이라구?","JPN":"一人でも多く殺したがるのが普通なのにさ。","ENG":"It's normal to want to kill more people, no?","TWN":"通常這種情況下，想要毀滅敵人才是正常的吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 사장님은 어째서 그런 부탁을 하셨을까요? 단순히 저와 같은 광인이라?","JPN":"だったら社長はどうしてそんなことを頼んだのでしょう？　単に私と同じ狂人だから？","ENG":"Then why would Boss make such a request? Simply because he is a lunatic like me?","TWN":"那老闆為什麼要說出那樣的請求呢？因為他是和我一樣的瘋子嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳은 어때요? 학회는 사라져야 한다고 생각하나요?","JPN":"リベットはどうですか？　学会はなくなるべきだと思いますか？","ENG":"What about you, Rivet? Do you also think that the Society should be abolished?","TWN":"里維是怎麼想的？你覺得學會必須消滅嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"당연하지. 난 너도 나도 인정하는 상식인이잖아.","JPN":"当たり前じゃん。アタシは、アンタもアタシも認める常識人だからね。","ENG":"Without a doubt. I'm a rational person, and we both admit that's true.","TWN":"當然。因為我是公認的正常人。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"없애지 말아야 할 이유를 찾아야겠네요. 당신이 찬성할 정도라면.","JPN":"なくしてはいけない理由を探さなければいけませんね。あなたが賛成するくらいなら。","ENG":"Then, I need to find a reason not to. Since even you agree with that.","TWN":"那我得找到不該消滅學會的理由了呢。如果這件事連你都贊成的話。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"우우, 폭군이다. 제멋대로에 성격도 나쁜 폭군.","JPN":"うう～暴君だ～自分勝手で性格も悪い暴君。","ENG":"Ooh, a tyrant. A bad tyrant with an even worse personality.","TWN":"嗚嗚，暴君，任性妄為、性格差勁的暴君。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시라도 다시 만나게 되면, 한 가지 물어 보고 싶었어요.","JPN":"もしまた会えたら、一つだけ聞きたかったことがあります。","ENG":"I wanted to ask you something if we were to ever meet again.","TWN":"如果能再見到你，我一直有一個問題想問你。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 시설에서 저를 데리고 도망쳤죠?","JPN":"どうして施設から私を連れて逃げたのですか？","ENG":"Why did you take me with you when you ran away from that facility?","TWN":"在設施裡，你為什麼帶著我逃走了？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 미치광이라도 에델과 척을 지는 짓이라는 걸 모르진 않았을 텐데요.","JPN":"いくら狂人でも、エデルに敵対することだと知っていたはずですのに。","ENG":"Even if you are insane, you knew not to make Edel your enemy.","TWN":"就算你是個瘋子，也應該知道這麼做會跟艾瑟兒結仇吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"사실 내가 네 진짜 엄마란다.","JPN":"実は、アタシがアンタの本当のお母さんなんだ。","ENG":"Well. I am your Mother.","TWN":"因為我才是你真正的媽媽。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};